const d = $input.first().json;
const habits = d.habits;
const goals = d.goals;

const habitList = habits.items
  .map(h => `  ${h.completed ? '✓' : '○'} ${h.name}`)
  .join('\n');

const goalList = goals.items.length
  ? goals.items.map(g => `  ${g.done ? '✓' : '○'} ${g.start_time || '--'} ${g.title}`).join('\n')
  : '  (Program oluşturulmamış)';

const review = d.review
  ? `\n📝 Akşam notu:\n  İyi giden: ${d.review.what_went_well || '-'}\n  Yarın odak: ${d.review.tomorrow_focus || '-'}`
  : '';

const subject = `Atomik Planner — ${d.date} | %${habits.rate} tamamlandı`;

const body = `Günün özeti — ${d.date}\n\n` +
  `📊 Alışkanlıklar: ${habits.completed}/${habits.total} (%${habits.rate})\n${habitList}\n\n` +
  `🗓 Hedefler: ${goals.completed}/${goals.total}\n${goalList}` +
  review;

return [{ json: { subject, body } }];
